type IrisAdminServiceHTTPClient interface {
	// ApplyKumoConfig ApplyKumoConfig renders the configuration, writes it to KumoMTA, and
	// reloads the service. High-risk: requires confirmation and is audited.
	ApplyKumoConfig(ctx context.Context, req *ApplyKumoConfigRequest, opts ...http.CallOption) (rsp *ApplyKumoConfigReply, err error)
	// ChangePassword ChangePassword updates the calling user's own password.
	ChangePassword(ctx context.Context, req *ChangePasswordRequest, opts ...http.CallOption) (rsp *ChangePasswordReply, err error)
	// CheckDomainBounceSetup CheckDomainBounceSetup verifies a domain's MX (accepts bounces here), SPF
	// (authorizes our egress IPs), and DKIM (selector records) via live DNS.
	CheckDomainBounceSetup(ctx context.Context, req *CheckDomainBounceSetupRequest, opts ...http.CallOption) (rsp *DomainBounceCheck, err error)
	ClearAcmeDnsProvider(ctx context.Context, req *ClearAcmeDnsProviderRequest, opts ...http.CallOption) (rsp *AcmeDnsProvider, err error)
	ConfirmMFA(ctx context.Context, req *ConfirmMFARequest, opts ...http.CallOption) (rsp *ConfirmMFAReply, err error)
	CreateDKIMDomain(ctx context.Context, req *CreateDKIMDomainRequest, opts ...http.CallOption) (rsp *DKIMDomain, err error)
	CreateFeedbackLoop(ctx context.Context, req *CreateFeedbackLoopRequest, opts ...http.CallOption) (rsp *FeedbackLoop, err error)
	CreateListener(ctx context.Context, req *CreateListenerRequest, opts ...http.CallOption) (rsp *Listener, err error)
	CreateRoutingRule(ctx context.Context, req *CreateRoutingRuleRequest, opts ...http.CallOption) (rsp *RoutingRule, err error)
	CreateSuppression(ctx context.Context, req *CreateSuppressionRequest, opts ...http.CallOption) (rsp *Suppression, err error)
	CreateTLSPolicy(ctx context.Context, req *CreateTLSPolicyRequest, opts ...http.CallOption) (rsp *TLSPolicy, err error)
	CreateUser(ctx context.Context, req *CreateUserRequest, opts ...http.CallOption) (rsp *User, err error)
	CreateVMTA(ctx context.Context, req *CreateVMTARequest, opts ...http.CallOption) (rsp *VMTA, err error)
	CreateVMTAGroups(ctx context.Context, req *CreateVMTAGroupRequest, opts ...http.CallOption) (rsp *VMTAGroup, err error)
	CreateWebhookRule(ctx context.Context, req *CreateWebhookRuleRequest, opts ...http.CallOption) (rsp *WebhookRule, err error)
	// CurrentUser CurrentUser returns the calling user's profile and effective permissions;
	// the SPA calls it on load to restore a session from a stored token.
	CurrentUser(ctx context.Context, req *CurrentUserRequest, opts ...http.CallOption) (rsp *CurrentUserReply, err error)
	DeleteAcmeCertificate(ctx context.Context, req *DeleteAcmeCertificateRequest, opts ...http.CallOption) (rsp *DeleteAcmeCertificateReply, err error)
	DeleteFeedbackLoop(ctx context.Context, req *DeleteFeedbackLoopRequest, opts ...http.CallOption) (rsp *DeleteFeedbackLoopReply, err error)
	DeleteTLSPolicy(ctx context.Context, req *DeleteTLSPolicyRequest, opts ...http.CallOption) (rsp *DeleteTLSPolicyReply, err error)
	// Diagnose Tools ---------------------------------------------------------------------
	// Diagnose reports how mail from a given address is handled and whether the
	// sending domain is set up correctly (DKIM/SPF/DMARC/MX/FBL + routing preview).
	Diagnose(ctx context.Context, req *DiagnoseRequest, opts ...http.CallOption) (rsp *DiagnoseResult, err error)
	DisableMFA(ctx context.Context, req *DisableMFARequest, opts ...http.CallOption) (rsp *DisableMFAReply, err error)
	// EnrollMFA MFA enrollment for the calling user (TOTP).
	EnrollMFA(ctx context.Context, req *EnrollMFARequest, opts ...http.CallOption) (rsp *EnrollMFAReply, err error)
	// GenerateDKIMKey Generate a fresh DKIM key pair. Returns the private key (to save on the
	// domain) and the public DNS TXT record to publish; nothing is persisted.
	GenerateDKIMKey(ctx context.Context, req *GenerateDKIMKeyRequest, opts ...http.CallOption) (rsp *GenerateDKIMKeyReply, err error)
	// GenerateKumoConfig GenerateKumoConfig renders the current Iris configuration into KumoMTA
	// policy without applying it (a preview/diff).
	GenerateKumoConfig(ctx context.Context, req *GenerateKumoConfigRequest, opts ...http.CallOption) (rsp *KumoConfig, err error)
	// GetAcmeAccount ACME (Let's Encrypt) -------------------------------------------------------
	GetAcmeAccount(ctx context.Context, req *GetAcmeAccountRequest, opts ...http.CallOption) (rsp *AcmeAccount, err error)
	GetAcmeDnsProvider(ctx context.Context, req *GetAcmeDnsProviderRequest, opts ...http.CallOption) (rsp *AcmeDnsProvider, err error)
	GetDashboardSummary(ctx context.Context, req *GetDashboardSummaryRequest, opts ...http.CallOption) (rsp *DashboardSummary, err error)
	// GetDmarcStats DMARC aggregate reports -----------------------------------------------------
	GetDmarcStats(ctx context.Context, req *GetDmarcStatsRequest, opts ...http.CallOption) (rsp *DmarcStats, err error)
	// GetGlobalSettings Global settings (deployment-level policy knobs editable in the UI).
	GetGlobalSettings(ctx context.Context, req *GetGlobalSettingsRequest, opts ...http.CallOption) (rsp *GlobalSettings, err error)
	// GetMetricsTimeseries GetMetricsTimeseries returns curated mail-flow time-series (deliveries,
	// bounces, deferrals, receptions) from the configured Prometheus.
	GetMetricsTimeseries(ctx context.Context, req *GetMetricsTimeseriesRequest, opts ...http.CallOption) (rsp *MetricsTimeseries, err error)
	// KumoConfigStatus KumoConfigStatus reports whether the current configuration has drifted from
	// the last applied policy (a regenerate/apply is pending).
	KumoConfigStatus(ctx context.Context, req *KumoConfigStatusRequest, opts ...http.CallOption) (rsp *KumoConfigStatusReply, err error)
	ListAcmeCertificates(ctx context.Context, req *ListAcmeCertificatesRequest, opts ...http.CallOption) (rsp *ListAcmeCertificatesReply, err error)
	// ListAcmeDnsProviders ACME DNS-01 challenge provider configuration.
	ListAcmeDnsProviders(ctx context.Context, req *ListAcmeDnsProvidersRequest, opts ...http.CallOption) (rsp *ListAcmeDnsProvidersReply, err error)
	ListAuditEntries(ctx context.Context, req *ListAuditEntriesRequest, opts ...http.CallOption) (rsp *ListAuditEntriesReply, err error)
	ListBounces(ctx context.Context, req *ListBouncesRequest, opts ...http.CallOption) (rsp *ListBouncesReply, err error)
	// ListDKIMDomains Domain & recipient safety ------------------------------------------------
	ListDKIMDomains(ctx context.Context, req *ListDKIMDomainsRequest, opts ...http.CallOption) (rsp *ListDKIMDomainsReply, err error)
	ListDmarcDomains(ctx context.Context, req *ListDmarcDomainsRequest, opts ...http.CallOption) (rsp *ListDmarcDomainsReply, err error)
	ListDmarcReports(ctx context.Context, req *ListDmarcReportsRequest, opts ...http.CallOption) (rsp *ListDmarcReportsReply, err error)
	// ListFeedbackLoops Feedback loops -----------------------------------------------------------
	// Per-domain FBL enrollments: while awaiting approval, inbound feedback mail
	// is forwarded to a human; once approved the domain enables the ARF parser.
	ListFeedbackLoops(ctx context.Context, req *ListFeedbackLoopsRequest, opts ...http.CallOption) (rsp *ListFeedbackLoopsReply, err error)
	ListFeedbackReports(ctx context.Context, req *ListFeedbackReportsRequest, opts ...http.CallOption) (rsp *ListFeedbackReportsReply, err error)
	// ListListeners Listeners (ESMTP) --------------------------------------------------------
	ListListeners(ctx context.Context, req *ListListenersRequest, opts ...http.CallOption) (rsp *ListListenersReply, err error)
	// ListMailRecords Mail operations ----------------------------------------------------------
	ListMailRecords(ctx context.Context, req *ListMailRecordsRequest, opts ...http.CallOption) (rsp *ListMailRecordsReply, err error)
	ListQueues(ctx context.Context, req *ListQueuesRequest, opts ...http.CallOption) (rsp *ListQueuesReply, err error)
	ListRoutingRules(ctx context.Context, req *ListRoutingRulesRequest, opts ...http.CallOption) (rsp *ListRoutingRulesReply, err error)
	ListRspamdResults(ctx context.Context, req *ListRspamdResultsRequest, opts ...http.CallOption) (rsp *ListRspamdResultsReply, err error)
	ListSuppressions(ctx context.Context, req *ListSuppressionsRequest, opts ...http.CallOption) (rsp *ListSuppressionsReply, err error)
	// ListTLSPolicies Require-TLS policies (outbound delivery must use TLS for these domains) ---
	ListTLSPolicies(ctx context.Context, req *ListTLSPoliciesRequest, opts ...http.CallOption) (rsp *ListTLSPoliciesReply, err error)
	// ListUsers Security administration --------------------------------------------------
	ListUsers(ctx context.Context, req *ListUsersRequest, opts ...http.CallOption) (rsp *ListUsersReply, err error)
	ListVMTAGroups(ctx context.Context, req *ListVMTAGroupsRequest, opts ...http.CallOption) (rsp *ListVMTAGroupsReply, err error)
	// ListVMTAs Outbound configuration ---------------------------------------------------
	ListVMTAs(ctx context.Context, req *ListVMTAsRequest, opts ...http.CallOption) (rsp *ListVMTAsReply, err error)
	// ListWebhookDeliveries Webhook delivery events (the outcomes of webhook fan-out).
	ListWebhookDeliveries(ctx context.Context, req *ListWebhookDeliveriesRequest, opts ...http.CallOption) (rsp *ListWebhookDeliveriesReply, err error)
	// ListWebhookRules Inbound automation -------------------------------------------------------
	ListWebhookRules(ctx context.Context, req *ListWebhookRulesRequest, opts ...http.CallOption) (rsp *ListWebhookRulesReply, err error)
	// Login Authentication -----------------------------------------------------------
	// Login exchanges email + password for a session token. It is exempt from the
	// auth middleware (the operation name contains "Login"). When MFA is required
	// the reply carries a partially-authenticated token plus a status indicating
	// the next step (verify an existing enrollment, or enroll first).
	Login(ctx context.Context, req *LoginRequest, opts ...http.CallOption) (rsp *LoginReply, err error)
	// Logout Logout is a no-op server-side for stateless tokens; provided so clients can
	// signal intent and the action is audited.
	Logout(ctx context.Context, req *LogoutRequest, opts ...http.CallOption) (rsp *LogoutReply, err error)
	// RblCheck RblCheck tests the deployment's listener and VMTA egress IPs against DNS
	// blocklists.
	RblCheck(ctx context.Context, req *RblCheckRequest, opts ...http.CallOption) (rsp *RblCheckReply, err error)
	// RequestAcmeCertificate RequestAcmeCertificate issues (or re-issues) a certificate via HTTP-01.
	// Synchronous: blocks for the ACME handshake.
	RequestAcmeCertificate(ctx context.Context, req *RequestAcmeCertificateRequest, opts ...http.CallOption) (rsp *AcmeCertificate, err error)
	RequestQueueAction(ctx context.Context, req *RequestQueueActionRequest, opts ...http.CallOption) (rsp *QueueActionReply, err error)
	// RequestServiceControl KumoMTA service & configuration ------------------------------------------
	RequestServiceControl(ctx context.Context, req *RequestServiceControlRequest, opts ...http.CallOption) (rsp *ServiceControlRequest, err error)
	// ResetUserPassword ResetUserPassword sets a new password for a user (admin reset). Requires
	// user:write; the new password is strength-validated and bcrypt-hashed.
	ResetUserPassword(ctx context.Context, req *ResetUserPasswordRequest, opts ...http.CallOption) (rsp *ResetUserPasswordReply, err error)
	SaveAcmeAccount(ctx context.Context, req *SaveAcmeAccountRequest, opts ...http.CallOption) (rsp *AcmeAccount, err error)
	SetAcmeDnsProvider(ctx context.Context, req *SetAcmeDnsProviderRequest, opts ...http.CallOption) (rsp *AcmeDnsProvider, err error)
	UpdateDKIMDomain(ctx context.Context, req *UpdateDKIMDomainRequest, opts ...http.CallOption) (rsp *DKIMDomain, err error)
	UpdateFeedbackLoop(ctx context.Context, req *UpdateFeedbackLoopRequest, opts ...http.CallOption) (rsp *FeedbackLoop, err error)
	UpdateGlobalSettings(ctx context.Context, req *UpdateGlobalSettingsRequest, opts ...http.CallOption) (rsp *GlobalSettings, err error)
	UpdateListener(ctx context.Context, req *UpdateListenerRequest, opts ...http.CallOption) (rsp *Listener, err error)
	UpdateRoutingRule(ctx context.Context, req *UpdateRoutingRuleRequest, opts ...http.CallOption) (rsp *RoutingRule, err error)
	UpdateSuppression(ctx context.Context, req *UpdateSuppressionRequest, opts ...http.CallOption) (rsp *Suppression, err error)
	UpdateUser(ctx context.Context, req *UpdateUserRequest, opts ...http.CallOption) (rsp *User, err error)
	UpdateVMTA(ctx context.Context, req *UpdateVMTARequest, opts ...http.CallOption) (rsp *VMTA, err error)
	UpdateVMTAGroup(ctx context.Context, req *UpdateVMTAGroupRequest, opts ...http.CallOption) (rsp *VMTAGroup, err error)
	UpdateWebhookRule(ctx context.Context, req *UpdateWebhookRuleRequest, opts ...http.CallOption) (rsp *WebhookRule, err error)
	// VerifyMFA VerifyMFA completes a login by validating a TOTP code, upgrading the
	// partially-authenticated session token to a fully-authenticated one.
	VerifyMFA(ctx context.Context, req *VerifyMFARequest, opts ...http.CallOption) (rsp *LoginReply, err error)
}

